/// Module demonstrating progressive disclosure pattern.
pub struct ProgressiveDisclosure {
    pub primary_options: Vec<String>,
    pub advanced_options: Vec<String>,
    pub show_advanced: bool,
}

impl ProgressiveDisclosure {
    pub fn new() -> Self {
        Self {
            // Primary: Always visible
            primary_options: vec![
                "Confirm".to_string(),
                "Cancel".to_string(),
            ],
            // Advanced: Hidden by default
            advanced_options: vec![
                "Always Allow".to_string(),
                "Skip This Step".to_string(),
            ],
            show_advanced: false,
        }
    }

    /// Get visible options based on disclosure state
    pub fn visible_options(&self) -> Vec<String> {
        let mut opts = self.primary_options.clone();
        if self.show_advanced {
            opts.extend(self.advanced_options.clone());
        }
        opts
    }

    /// Show advanced options
    pub fn reveal_advanced(&mut self) {
        self.show_advanced = true;
    }

    /// Hide advanced options
    pub fn hide_advanced(&mut self) {
        self.show_advanced = false;
    }
}
